const item = $input.first();
const form = item.json;

const vendorName = form['Vendor Name'] || 'Unknown Vendor';
const vendorCategory = form['Vendor Category'] || 'Other';
const submitterEmail = form['Submitter Email'] || '';
const packetReference = form['Packet Reference'] || '';

const vendorSlug = vendorName.toUpperCase().replace(/[^A-Z0-9]/g, '_').substring(0, 20);
const timestamp = new Date().toISOString().replace(/[-:T]/g, '').substring(0, 14);
const packetId = 'PKT-' + vendorSlug + '-' + timestamp;
const today = new Date().toISOString().split('T')[0];

const checklists = {
  'IT Services': ['contract', 'compliance_certificate', 'data_privacy_agreement', 'vendor_registration'],
  'Financial Services': ['contract', 'compliance_certificate', 'financial_statement', 'vendor_registration', 'insurance_certificate'],
  'Legal & Compliance': ['contract', 'vendor_registration', 'insurance_certificate'],
  'HR & Payroll': ['contract', 'data_privacy_agreement', 'vendor_registration'],
  'Other': ['contract', 'vendor_registration'],
};
const expectedDocs = checklists[vendorCategory] || checklists['Other'];

// Read ALL binary keys — n8n names them Upload_Documents, Upload_Documents_1, Upload_Documents_2 etc.
const binaryKeys = Object.keys(item.binary || {});

const files = binaryKeys.map((key, index) => {
  const bin = item.binary[key];
  return {
    file_index:  index,
    filename:    bin.fileName || bin.filename || 'file_' + index,
    mimetype:    bin.mimeType || bin.mimetype || 'application/octet-stream',
    file_size:   bin.fileSize || bin.bytes || 0,
    binary_key:  key,  // Upload_Documents, Upload_Documents_1, Upload_Documents_2 etc.
  };
});

return [{
  json: {
    packet_id:        packetId,
    vendor_name:      vendorName,
    vendor_category:  vendorCategory,
    submitter_email:  submitterEmail,
    packet_reference: packetReference || packetId,
    today:            today,
    expected_docs:    expectedDocs,
    total_files:      files.length,
    files:            files,
    submitted_at:     new Date().toISOString(),
  },
  binary: item.binary,
}];

const packet = $input.first();
const data = packet.json;
const allBinary = packet.binary || {};

if (!data.files || data.files.length === 0) {
  return [{ json: { error: true, error_message: 'No files found' } }];
}

const items = data.files.map((file) => {
  const itemBinary = {};
  if (file.binary_key && allBinary[file.binary_key]) {
    itemBinary['file_data'] = allBinary[file.binary_key];
  }

  return {
    json: {
      file_index:       file.file_index,
      filename:         file.filename,
      mimetype:         file.mimetype,
      file_size:        file.file_size,
      binary_key:       'file_data',
      // Add unique item marker — this survives through Extract from File for CSV
      item_marker:      `ITEM_${file.file_index}_${file.filename}`,

      packet_id:        data.packet_id,
      vendor_name:      data.vendor_name,
      vendor_category:  data.vendor_category,
      submitter_email:  data.submitter_email,
      packet_reference: data.packet_reference,
      today:            data.today,
      expected_docs:    data.expected_docs,
      total_files:      data.files.length,
      submitted_at:     data.submitted_at,
    },
    binary: itemBinary,
  };
});

return items;

const allExtractItems = $input.all();
const allSplitItems = $('Split Files into Items').all();

const results = allExtractItems.map((extractItem, index) => {
  const extractData = extractItem.json;
  const extractedText = extractData.text || extractData.data || '';

  // Try to match using item_marker if Extract from File preserved it
  let splitData = null;

  if (extractData.item_marker) {
    splitData = allSplitItems.find(s =>
      s.json.item_marker === extractData.item_marker
    )?.json;
  }

  // Fallback: match PDF items positionally
  if (!splitData) {
    const pdfSplitItems = allSplitItems.filter(s =>
      (s.json.mimetype || '').includes('pdf') ||
      (s.json.filename || '').endsWith('.pdf')
    );
    splitData = pdfSplitItems[index]?.json;
  }

  // Final fallback
  if (!splitData) {
    splitData = allSplitItems[index]?.json || allSplitItems[0].json;
  }

  return {
    json: {
      file_index:         splitData.file_index,
      filename:           splitData.filename,
      mimetype:           splitData.mimetype,
      file_size:          splitData.file_size,
      binary_key:         splitData.binary_key,
      packet_id:          splitData.packet_id,
      vendor_name:        splitData.vendor_name,
      vendor_category:    splitData.vendor_category,
      submitter_email:    splitData.submitter_email,
      packet_reference:   splitData.packet_reference,
      today:              splitData.today,
      expected_docs:      splitData.expected_docs,
      total_files:        splitData.total_files,
      submitted_at:       splitData.submitted_at,
      extracted_text:     extractedText,
      extraction_method:  'pdf_native',
      is_image:           false,
      is_base64:          false,
      extraction_success: extractedText.length > 0,
    },
    binary: extractItem.binary || {},
  };
});

return results;

const allExtractItems = $input.all();
const allSplitItems = $('Split Files into Items').all();

// Find the CSV item in Split Files
const csvSplitItem = allSplitItems.find(s =>
  (s.json.mimetype || '').includes('csv') ||
  (s.json.filename || '').endsWith('.csv')
)?.json;

// If no CSV found, find XLSX
const xlsxSplitItem = !csvSplitItem ? allSplitItems.find(s =>
  (s.json.mimetype || '').includes('spreadsheet') ||
  (s.json.filename || '').endsWith('.xlsx')
)?.json : null;

const meta = csvSplitItem || xlsxSplitItem || allSplitItems[0]?.json || {};

// Convert all CSV rows to readable text
const lines = [];
for (const item of allExtractItems) {
  const row = item.json;
  const skipKeys = ['packet_id','vendor_name','vendor_category','submitter_email',
    'packet_reference','today','expected_docs','total_files','submitted_at',
    'file_index','filename','mimetype','file_size','binary_key','item_marker',
    'text','numpages','numrender','info','version','data'];
  const values = Object.entries(row)
    .filter(([k]) => !skipKeys.includes(k))
    .map(([k, v]) => String(v || '').trim())
    .filter(v => v.length > 0);
  if (values.length > 0) {
    lines.push(values.join(' | '));
  }
}

const extractedText = lines.join('\n');

return [{
  json: {
    file_index:         meta.file_index,
    filename:           meta.filename,
    mimetype:           meta.mimetype,
    file_size:          meta.file_size,
    binary_key:         meta.binary_key,
    packet_id:          meta.packet_id,
    vendor_name:        meta.vendor_name,
    vendor_category:    meta.vendor_category,
    submitter_email:    meta.submitter_email,
    packet_reference:   meta.packet_reference,
    today:              meta.today,
    expected_docs:      meta.expected_docs,
    total_files:        meta.total_files,
    submitted_at:       meta.submitted_at,
    extracted_text:     extractedText,
    extraction_method:  'csv_native',
    is_image:           false,
    is_base64:          false,
    extraction_success: extractedText.length > 0,
  },
  binary: {},
}];

const allExtractItems = $input.all();
const allSplitItems = $('Split Files into Items').all();

const lines = [];
let splitData = null;

for (const item of allExtractItems) {
  const row = item.json;

  // Get split data from first item that has filename
  if (!splitData && row.filename) {
    splitData = row;
  }

  const skipKeys = ['packet_id','vendor_name','vendor_category','submitter_email',
    'packet_reference','today','expected_docs','total_files','submitted_at',
    'file_index','filename','mimetype','file_size','binary_key','text','numpages',
    'numrender','info','version','data'];
  const values = Object.entries(row)
    .filter(([k]) => !skipKeys.includes(k))
    .map(([k, v]) => String(v || '').trim())
    .filter(v => v.length > 0);
  if (values.length > 0) {
    lines.push(values.join(' | '));
  }
}

const extractedText = lines.join('\n');
const meta = splitData || allSplitItems[0]?.json || {};

return [{
  json: {
    file_index:         meta.file_index,
    filename:           meta.filename,
    mimetype:           meta.mimetype,
    file_size:          meta.file_size,
    binary_key:         meta.binary_key,
    packet_id:          meta.packet_id,
    vendor_name:        meta.vendor_name,
    vendor_category:    meta.vendor_category,
    submitter_email:    meta.submitter_email,
    packet_reference:   meta.packet_reference,
    today:              meta.today,
    expected_docs:      meta.expected_docs,
    total_files:        meta.total_files,
    submitted_at:       meta.submitted_at,
    extracted_text:     extractedText,
    extraction_method:  'xlsx_native',
    is_image:           false,
    is_base64:          false,
    extraction_success: extractedText.length > 0,
  },
  binary: {},
}];

const allItems = $input.all();

const results = allItems.map((item, currentIndex) => {
  const data = item.json;

  const systemPrompt = `You are a document intelligence agent for a vendor risk management platform. Your job is to analyse vendor onboarding documents and return structured JSON output. You are precise, thorough, and conservative — when in doubt, flag rather than ignore.

CRITICAL RULES:
1. Return ONLY valid JSON. No prose, no markdown code fences, no explanation before or after. Your entire response must be parseable by JSON.parse().
2. Never invent or hallucinate field values. If a field is not present in the document, set "value": null and "present": false.
3. Today's date is ${data.today}. Use this to calculate days_until_expiry for all date fields.
4. Return confidence scores honestly. If text is unclear, handwritten, or partially obscured, confidence must reflect this (below 0.7).
5. For flags: be specific. Include exact values, dates, and clause names in the detail field.
6. The document_name field in your JSON response MUST be set to exactly the filename provided in the user message — do not modify, shorten, or change it in any way.

DOCUMENT TYPES you can classify:
- vendor_registration
- compliance_certificate
- contract
- financial_statement
- data_privacy_agreement
- insurance_certificate
- unknown

For vendor_registration extract: legal_entity_name, cin_or_registration_number, entity_type, incorporation_date, jurisdiction, registered_address, pan_number, gst_number, directors, ubo_declaration, primary_contact_name, primary_contact_email, bank_details_present

For compliance_certificate extract: certification_body, standard_name, certificate_number, scope, issue_date, expiry_date, days_until_expiry, accreditation_body, covered_entities, renewal_conditions

For contract extract: parties, effective_date, term_duration, auto_renewal, governing_law, jurisdiction, payment_terms, liability_cap_present, indemnification_present, ip_ownership, termination_notice_days, sla_uptime_percentage, dispute_resolution, data_protection_clause_present

For financial_statement extract: period, revenue_current, revenue_prior, revenue_yoy_change_pct, net_profit, ebitda, total_assets, total_liabilities, total_equity, debt_to_equity_ratio, auditor_name, audit_opinion, going_concern_note, currency, restatements_present

For data_privacy_agreement extract: controller_name, processor_name, personal_data_categories, processing_purpose, retention_period, sub_processors_listed, sub_processors, data_residency_declared, actual_infrastructure_locations, breach_notification_period, dpo_contact, gdpr_basis, cross_border_transfer_mechanism

For insurance_certificate extract: insurer_name, policy_number, coverage_type, coverage_limit, effective_date, expiry_date, days_until_expiry, named_insured, additional_insured, exclusions

FLAGGING RULES:
- expiry_imminent: days_until_expiry <= 90. Severity = critical if <= 30, high if <= 90.
- missing_clause: contract missing liability_cap_present=false or indemnification_present=false. Severity = critical.
- financial_anomaly: revenue drop > 20% YoY, OR audit_opinion is qualified or adverse, OR going_concern_note is true, OR debt_to_equity > 5. Severity = critical. One flag per anomaly.
- regulatory_risk: sub_processors_listed false, OR data residency conflict, OR breach_notification_period null. Severity = high per issue.
- certification_scope_gap: certificate scope does not cover vendor primary activity. Severity = medium.
- incomplete_submission: required fields null or unreadable. Severity = medium.

Return exactly this JSON structure:
{
  "packet_id": "",
  "document_name": "",
  "document_type": "",
  "classification_confidence": 0.0,
  "processing_mode": "single_pass",
  "extracted_fields": {},
  "flags": [],
  "completeness_check": {"expected_fields_present": true, "missing_expected_fields": []},
  "needs_verification_fields": [],
  "recommended_action": "",
  "action_reason": "",
  "summary": ""
}`;

  let messageContent;

  if (data.is_image) {
    messageContent = `Analyse the following document and return the JSON output as instructed.

Packet ID: ${data.packet_id}
Document filename: ${data.filename}
Vendor name: ${data.vendor_name}
Today's date: ${data.today}

IMPORTANT: You must set document_name in your JSON response to exactly this value: "${data.filename}" — do not change, shorten, or modify this filename in any way.

NOTE: This document is an image file (${data.media_type || 'image'}) named "${data.filename}". The image content could not be automatically extracted in this environment. Please:
1. Set document_name to exactly "${data.filename}"
2. Classify document_type as "insurance_certificate" based on the filename
3. Return empty extracted_fields with present: false and confidence: 0 for all insurance_certificate fields
4. Raise one incomplete_submission flag noting the image requires manual review
5. Set recommended_action to "review"
6. Note in summary that this is an image requiring manual extraction`;
  } else {
    messageContent = `Analyse the following document and return the JSON output as instructed.

Packet ID: ${data.packet_id}
Document filename: ${data.filename}
Vendor name: ${data.vendor_name}
Today's date: ${data.today}

IMPORTANT: You must set document_name in your JSON response to exactly this value: "${data.filename}" — do not change, shorten, or modify this filename in any way.

Document content:
${data.extracted_text}`;
  }

  const requestBody = {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 2000,
    system: systemPrompt,
    messages: [{
      role: 'user',
      content: messageContent,
    }]
  };

  return {
    json: {
      ...data,
      claude_request_body: JSON.stringify(requestBody),
    }
  };
});

return results;

const allItems = $input.all();

const results = allItems.map(item => {
  const data = item.json;

  const severityRank = { critical: 4, high: 3, medium: 2, low: 1 };
  const flagWeights = {
    expiry_imminent:        10,
    missing_clause:          9,
    financial_anomaly:       9,
    regulatory_risk:         7,
    data_inconsistency:      7,
    incomplete_submission:   5,
    certification_scope_gap: 4,
    unknown:                 3,
  };

  const normalisedFlags = (data.flags || []).map((flag, index) => {
    const flagType = flag.flag_type || flag.type || 'unknown';

    const titleMap = {
      expiry_imminent:        'Certificate or document expiring imminently',
      missing_clause:         'Required contract clause missing',
      financial_anomaly:      'Financial anomaly detected',
      regulatory_risk:        'Regulatory compliance risk',
      data_inconsistency:     'Cross-document data conflict',
      incomplete_submission:  'Incomplete or unreadable submission',
      certification_scope_gap:'Certification scope gap detected',
    };
    const title = flag.title && flag.title !== 'Unnamed flag'
      ? flag.title
      : (titleMap[flagType] || 'Risk flag detected');

    const fieldRef = flag.field_reference && flag.field_reference !== 'unspecified'
      ? flag.field_reference
      : (flag.affected_field || flag.field || 'unspecified');

    let daysUntilExpiry = flag.days_until_expiry;
    if (!daysUntilExpiry && flagType === 'expiry_imminent') {
      const daysField = data.extracted_fields?.days_until_expiry?.value;
      daysUntilExpiry = daysField || null;
    }

    const severityScore = severityRank[flag.severity] || 1;
    const typeWeight = flagWeights[flagType] || 3;
    const urgencyScore = severityScore * typeWeight;

    return {
      flag_id:           `FLAG_${String(index + 1).padStart(3, '0')}`,
      flag_type:         flagType,
      severity:          flag.severity || 'medium',
      title:             title,
      detail:            flag.detail || '',
      field_reference:   fieldRef,
      days_until_expiry: daysUntilExpiry,
      urgency_score:     urgencyScore,
    };
  });

  const totalUrgencyScore = normalisedFlags.reduce((sum, f) => sum + f.urgency_score, 0);

  const needsVerification = [];
  const extractedFields = data.extracted_fields || {};
  for (const [fieldName, fieldData] of Object.entries(extractedFields)) {
    if (fieldData && typeof fieldData === 'object' && fieldData.confidence < 0.7) {
      needsVerification.push(fieldName);
    }
  }

  const actionMap = {
    approve:              'approve',
    review:               'review',
    escalate:             'escalate',
    block:                'block',
    urgent_renewal_required: 'escalate',
    immediate_escalation: 'escalate',
    flag:                 'review',
    hold:                 'review',
  };
  const recommendedAction = actionMap[data.recommended_action] || 'review';

  const severityToAction = {
    critical: 'escalate',
    high:     'review',
    medium:   'review',
    low:      'approve',
    none:     'approve',
  };
  const actionFromSeverity = severityToAction[data.max_severity] || 'review';
  const finalAction = actionFromSeverity === 'escalate' ? 'escalate' : recommendedAction;

  return {
    json: {
      packet_id:               data.packet_id,
      document_name:           data.document_name,
      document_type:           data.document_type,
      classification_confidence: data.classification_confidence,
      vendor_name:             data.vendor_name,
      vendor_category:         data.vendor_category,
      submitter_email:         data.submitter_email,
      packet_reference:        data.packet_reference,
      today:                   data.today,
      expected_docs:           data.expected_docs,
      total_files:             data.total_files,
      submitted_at:            data.submitted_at,
      filename:                data.filename,
      extracted_fields:        extractedFields,
      flags:                   normalisedFlags,
      flag_count:              normalisedFlags.length,
      max_severity:            data.max_severity,
      total_urgency_score:     totalUrgencyScore,
      needs_verification_fields: needsVerification,
      completeness_check:      data.completeness_check,
      recommended_action:      finalAction,
      action_reason:           data.action_reason,
      summary:                 data.summary,
      token_usage:             data.token_usage,
    }
  };
});

return results;

const allItems = $input.all();

const results = allItems.map(rawItem => {
  const rawResponse = rawItem.json;

  const textContent = rawResponse.content[0].text;

  let parsed;
  try {
    parsed = JSON.parse(textContent);
  } catch (e) {
    return {
      json: {
        parse_error: true,
        error_message: e.message,
        packet_id: 'PARSE_ERROR',
        document_type: 'unknown',
        flags: [],
        recommended_action: 'block',
        action_reason: 'Claude response could not be parsed as valid JSON',
        summary: 'Parsing failed — manual review required',
      }
    };
  }

  // Normalise recommended_action
  const actionMap = {
    approve:                 'approve',
    review:                  'review',
    escalate:                'escalate',
    block:                   'block',
    urgent_renewal_required: 'escalate',
    immediate_escalation:    'escalate',
    require_amendment:       'escalate',
    flag:                    'review',
    hold:                    'review',
  };
  parsed.recommended_action = actionMap[parsed.recommended_action] || 'review';

  if (!parsed.flags) parsed.flags = [];

  parsed.flags = parsed.flags.map((flag, index) => {
    const flagType = flag.flag_type || flag.type || flag.flagType || 'unknown';

    let daysUntilExpiry = flag.days_until_expiry || flag.daysUntilExpiry || null;
    if (!daysUntilExpiry && flagType === 'expiry_imminent' && parsed.extracted_fields) {
      const dueField = parsed.extracted_fields.days_until_expiry;
      daysUntilExpiry = dueField ? (dueField.value || null) : null;
    }

    return {
      flag_id:           flag.flag_id || `FLAG_${String(index + 1).padStart(3, '0')}`,
      flag_type:         flagType,
      severity:          flag.severity || 'medium',
      title:             flag.title || flagType,
      detail:            flag.detail || '',
      field_reference:   flag.field_reference || flag.affected_field || flag.field || 'unspecified',
      days_until_expiry: daysUntilExpiry,
    };
  });

  // Compute max_severity
  const severityRank = { critical: 4, high: 3, medium: 2, low: 1 };
  const maxSeverityRank = parsed.flags.reduce((max, flag) => {
    return Math.max(max, severityRank[flag.severity] || 0);
  }, 0);
  const rankToSeverity = { 4: 'critical', 3: 'high', 2: 'medium', 1: 'low', 0: 'none' };
  parsed.max_severity = rankToSeverity[maxSeverityRank];

  parsed.token_usage = {
    input_tokens:  rawResponse.usage?.input_tokens || 0,
    output_tokens: rawResponse.usage?.output_tokens || 0,
  };

  // Restore packet metadata from Build Claude Request node
  // Match by filename since items may be in different order
  const allBuildItems = $('Build Claude Request').all();

// Primary: match by exact filename Claude returned
let matchedBuild = allBuildItems.find(b =>
  b.json.filename === parsed.document_name
)?.json;

// Secondary: match by partial filename
if (!matchedBuild) {
  matchedBuild = allBuildItems.find(b => {
    const buildName = (b.json.filename || '').toLowerCase();
    const parsedName = (parsed.document_name || '').toLowerCase();
    return buildName.length > 5 && parsedName.includes(buildName.substring(0, 10));
  })?.json;
}

// Final: use index but also override document_name with correct filename
const currentIndex = allItems.indexOf(rawItem);
if (!matchedBuild) {
  matchedBuild = allBuildItems[currentIndex]?.json || allBuildItems[0].json;
}

// Always override document_name with the correct filename from Build Claude Request
// This ensures the filename in output always matches the actual file processed
parsed.document_name = matchedBuild.filename || parsed.document_name;

  return {
    json: {
      ...parsed,
      vendor_name:       matchedBuild.vendor_name,
      vendor_category:   matchedBuild.vendor_category,
      submitter_email:   matchedBuild.submitter_email,
      packet_reference:  matchedBuild.packet_reference,
      filename:          matchedBuild.filename,
      today:             matchedBuild.today,
      expected_docs:     matchedBuild.expected_docs,
      total_files:       matchedBuild.total_files,
      submitted_at:      matchedBuild.submitted_at,
      extraction_method: matchedBuild.extraction_method,
    }
  };
});

return results;

const allItems = $input.all();

const results = allItems.map(item => {
  const data = item.json;
  const extractedFields = data.extracted_fields || {};

  // ── Part 1: Document-level field completeness ─────────────────────────
  const missingFields = [];
  const lowConfidenceFields = [...(data.needs_verification_fields || [])];

  for (const [fieldName, fieldData] of Object.entries(extractedFields)) {
    if (!fieldData || fieldData.value === null || fieldData.present === false) {
      missingFields.push(fieldName);
    }
  }

  const completenessFlags = [];
  if (missingFields.length > 0) {
    completenessFlags.push({
      flag_id:           `FLAG_COMPLETE_${String(data.flags.length + 1).padStart(3, '0')}`,
      flag_type:         'incomplete_submission',
      severity:          'medium',
      title:             'Required fields missing or unreadable',
      detail:            `The following fields could not be extracted from ${data.document_name}: ${missingFields.join(', ')}`,
      field_reference:   missingFields[0],
      days_until_expiry: null,
      urgency_score:     10,
    });
  }

  // ── Part 2: Specific critical field checks by document type ───────────
  const criticalFieldFlags = [];

  if (data.document_type === 'contract') {
    const liabilityCap = extractedFields.liability_cap_present;
    const indemnification = extractedFields.indemnification_present;

    if (liabilityCap && liabilityCap.value === false) {
      criticalFieldFlags.push({
        flag_id:           'FLAG_CONTRACT_001',
        flag_type:         'missing_clause',
        severity:          'critical',
        title:             'Liability cap clause missing',
        detail:            'Contract does not contain a liability cap clause. This is a critical risk — unlimited liability exposure.',
        field_reference:   'liability_cap_present',
        days_until_expiry: null,
        urgency_score:     36,
      });
    }

    if (indemnification && indemnification.value === false) {
      criticalFieldFlags.push({
        flag_id:           'FLAG_CONTRACT_002',
        flag_type:         'missing_clause',
        severity:          'critical',
        title:             'Indemnification clause missing',
        detail:            'Contract does not contain an indemnification clause. Legal exposure without indemnification protection.',
        field_reference:   'indemnification_present',
        days_until_expiry: null,
        urgency_score:     36,
      });
    }
  }

  if (data.document_type === 'data_privacy_agreement') {
    const subProcessors = extractedFields.sub_processors_listed;
    const breachNotification = extractedFields.breach_notification_period;
    const dataResidency = extractedFields.data_residency_declared;
    const actualInfra = extractedFields.actual_infrastructure_locations;

    if (subProcessors && subProcessors.value === false) {
      criticalFieldFlags.push({
        flag_id:           'FLAG_DPA_001',
        flag_type:         'regulatory_risk',
        severity:          'high',
        title:             'Sub-processors not listed',
        detail:            'DPA does not list approved sub-processors as required under GDPR Article 28 and DPDP Act 2023.',
        field_reference:   'sub_processors_listed',
        days_until_expiry: null,
        urgency_score:     21,
      });
    }

    if (breachNotification && (breachNotification.value === null || breachNotification.value === '')) {
      criticalFieldFlags.push({
        flag_id:           'FLAG_DPA_002',
        flag_type:         'regulatory_risk',
        severity:          'high',
        title:             'Breach notification period not specified',
        detail:            'DPA does not specify a breach notification timeline. DPDP Act and GDPR both require defined notification periods.',
        field_reference:   'breach_notification_period',
        days_until_expiry: null,
        urgency_score:     21,
      });
    }

    if (dataResidency && actualInfra) {
      const declared = String(dataResidency.value || '').toLowerCase();
      const actual = String(actualInfra.value || '').toLowerCase();
      if (actual && actual !== 'null' && actual !== '' && !actual.includes(declared.split(',')[0])) {
        criticalFieldFlags.push({
          flag_id:           'FLAG_DPA_003',
          flag_type:         'regulatory_risk',
          severity:          'high',
          title:             'Data residency conflict detected',
          detail:            `Declared residency is "${dataResidency.value}" but actual infrastructure includes "${actualInfra.value}". Cross-border transfer mechanism required.`,
          field_reference:   'actual_infrastructure_locations',
          days_until_expiry: null,
          urgency_score:     21,
        });
      }
    }
  }

  if (data.document_type === 'financial_statement') {
    const auditOpinion = extractedFields.audit_opinion;
    const goingConcern = extractedFields.going_concern_note;

    if (auditOpinion && ['qualified', 'adverse', 'disclaimer'].includes(
      String(auditOpinion.value || '').toLowerCase())) {
      criticalFieldFlags.push({
        flag_id:           'FLAG_FIN_001',
        flag_type:         'financial_anomaly',
        severity:          'critical',
        title:             'Qualified or adverse audit opinion',
        detail:            `Auditor issued a ${auditOpinion.value} opinion. This indicates material financial risk.`,
        field_reference:   'audit_opinion',
        days_until_expiry: null,
        urgency_score:     36,
      });
    }

    if (goingConcern && goingConcern.value === true) {
      criticalFieldFlags.push({
        flag_id:           'FLAG_FIN_002',
        flag_type:         'financial_anomaly',
        severity:          'critical',
        title:             'Going concern note present',
        detail:            'Auditor has raised a going concern note indicating material uncertainty about the vendor continuing as a business.',
        field_reference:   'going_concern_note',
        days_until_expiry: null,
        urgency_score:     36,
      });
    }
  }

  // ── Merge all flags ───────────────────────────────────────────────────
  const allFlags = [
    ...data.flags,
    ...completenessFlags,
    ...criticalFieldFlags,
  ];

  const severityRank = { critical: 4, high: 3, medium: 2, low: 1 };
  const maxSeverityRank = allFlags.reduce((max, flag) => {
    return Math.max(max, severityRank[flag.severity] || 0);
  }, 0);
  const rankToSeverity = { 4: 'critical', 3: 'high', 2: 'medium', 1: 'low', 0: 'none' };
  const maxSeverity = rankToSeverity[maxSeverityRank];

  const totalUrgencyScore = allFlags.reduce((sum, f) => sum + (f.urgency_score || 0), 0);

  const severityToAction = {
    critical: 'escalate',
    high:     'review',
    medium:   'review',
    low:      'approve',
    none:     'approve',
  };
  const finalAction = severityToAction[maxSeverity] || 'review';

  return {
    json: {
      packet_id:                data.packet_id,
      document_name:            data.document_name,
      document_type:            data.document_type,
      classification_confidence: data.classification_confidence,
      filename:                 data.filename,
      vendor_name:              data.vendor_name,
      vendor_category:          data.vendor_category,
      submitter_email:          data.submitter_email,
      packet_reference:         data.packet_reference,
      today:                    data.today,
      expected_docs:            data.expected_docs,
      total_files:              data.total_files,
      submitted_at:             data.submitted_at,
      extracted_fields:         extractedFields,
      flags:                    allFlags,
      flag_count:               allFlags.length,
      max_severity:             maxSeverity,
      total_urgency_score:      totalUrgencyScore,
      missing_fields:           missingFields,
      needs_verification_fields: lowConfidenceFields,
      completeness_check:       data.completeness_check,
      current_doc_type:         data.document_type,
      recommended_action:       finalAction,
      action_reason:            data.action_reason,
      summary:                  data.summary,
      token_usage:              data.token_usage,
    }
  };
});

